import { describe, it, expect } from "vitest";
import { processScenario } from "./engine.js";

describe("MHPCO Claim Office - Quote", () => {
  // Base premiums
  it.todo("empty item list → premium 5 G (only processing fee)");
  it.todo("single sword → premium 115 G (100 base + 10 first-insurance + 5 fee)");
  it.todo("single amulet → premium 75 G (60 base + 10 first-insurance + 5 fee)");
  it.todo("single staff → premium 95 G (80 base + 10 first-insurance + 5 fee)");
  it.todo("single potion → premium 55 G (40 base + 10 first-insurance + 5 fee)");
  it.todo("single rune → premium 40 G (25 base + 10 first-insurance + 5 fee)");
  it.todo("single moonstone → premium 40 G (25 base + 10 first-insurance + 5 fee)");

  // Component blocks
  it.todo("2 runes → premium 65 G (50 base + 10 first-insurance + 5 fee)");
  it.todo("3 runes → premium 75 G (60 block base + 10 first-insurance + 5 fee)");
  it.todo("4 runes → premium 115 G (100 base + 10 first-insurance + 5 fee)");
  it.todo("7 runes → premium 190 G (175 base + 10 first-insurance + 5 fee)");
  it.todo("2 runes + 1 moonstone → premium 90 G (75 base + 10 first-insurance + 5 fee, no block: different types)");
  it.todo("3 runes + 3 moonstones → premium 135 G (120 base + 10 first-insurance + 5 fee, two separate blocks)");

  // Item-specific modifiers
  it.todo("cursed sword → premium 165 G (100 base + 50 curse + 10 first-insurance + 5 fee)");
  it.todo("sword with enchantment 5 → premium 145 G (100 base + 30 high-enchantment + 10 first-insurance + 5 fee)");
  it.todo("cursed sword with enchantment 5 → premium 195 G (100 base + 50 curse + 30 high-enchantment + 10 first-insurance + 5 fee)");
  it.todo("sword with enchantment 4 → premium 115 G (no high-enchantment surcharge)");

  // Policy-wide modifiers
  it.todo("sword for customer with exactly 2 years → premium 95 G (100 base + 10 first-insurance - 20 loyalty + 5 fee)");
  it.todo("sword for customer with 0 years → premium 115 G (no loyalty discount)");
  it.todo("second quote for sword → premium 100 G (100 base + 10 first-insurance - 15 follow-up + 5 fee)");
  it.todo("second quote for sword with 2 years loyalty → premium 80 G (100 base + 10 first-insurance - 20 loyalty - 15 follow-up + 5 fee)");

  // Modifier scope on multi-item policies
  it.todo("cursed sword + plain amulet for new customer → premium 231 G (160 policy-base + 50 curse + 16 first-insurance + 5 fee)");
  it.todo("cursed sword + plain amulet for 2-year customer → premium 199 G (160 policy-base + 50 curse - 32 loyalty + 16 first-insurance + 5 fee)");

  // Integration examples
  it.todo("newcomer with cursed sword (enchantment 3) → premium 165 G (100 base + 50 curse + 10 first-insurance + 5 fee)");
  it.todo("long-standing customer's second contract: cursed sword (enchantment 7), 3 years → premium 160 G (100 base + 50 curse + 30 high-enchantment - 20 loyalty + 10 first-insurance - 15 follow-up + 5 fee)");

  // Rounding
  it.todo("premium calculation yielding 197.5 G → rounds up to 198 G");

  // Error cases
  it.todo("unknown item type (e.g. broomstick) → throws error");
});

describe("MHPCO Claim Office - Claim", () => {
  // Standard reimbursement
  it.todo("regular sword (steel, enchantment 3), damage 500 G → payout 400 G (full reimbursement minus 100 deductible)");
  it.todo("rune damage 200 G → payout 100 G (full reimbursement minus 100 deductible)");

  // High enchantment
  it.todo("steel sword enchantment 9, damage 1000 G → payout 400 G (50% rule: 500 - 100 deductible)");
  it.todo("dragon-material sword enchantment 9, damage 1000 G → payout 400 G (50% rule wins over dragon material: 500 - 100 deductible)");
  it.todo("dragon-material sword enchantment 5, damage 800 G → payout 700 G (dragon material full reimbursement: 800 - 100 deductible)");

  // Multiple items damaged
  it.todo("sword 500 G + amulet 300 G in one incident → payout 600 G (100 deductible per damaged item)");

  // Cap
  it.todo("policy with sword + amulet, insurance sum 1600 G, cap 3200 G");
  it.todo("cursed sword, insurance sum 1000 G, cap 2000 G (premium modifiers do not raise cap)");
  it.todo("sword + 3 runes, insurance sum 1750 G, cap 3500 G (block discount affects premium only)");
  it.todo("two swords, insurance sum 2000 G, cap 4000 G");

  // Cap exhaustion
  it.todo("sword insured, first claim 1500 G → payout 1400 G, remaining cap 600 G");
  it.todo("sword insured, second claim 1500 G after first → payout 600 G, remaining cap 0 G");

  // Multiple items of same type
  it.todo("two swords insured, two sword damages → each treated as separate damage with own deductible");
  it.todo("two damages for item type but only one insured → throws error");

  // Rounding
  it.todo("payout calculation yielding 350.5 G → rounds down to 350 G");

  // Error cases
  it.todo("claim for item not in policy → throws error");
  it.todo("claim with unknown item type → throws error");
  it.todo("claim with negative damage amount → throws error");
});

describe("MHPCO Claim Office - Full Scenarios", () => {
  it.todo("quote then claim: amulet quoted then damaged by fire → premium and payout correct");
});

import { describe, it, expect } from "vitest";
import { processScenario } from "./engine.js";

describe("MHPCO Claim Office - CLI", () => {
  it.todo("full scenario: quote then claim outputs correct JSON");
  it.todo("unknown item type in quote exits with error");
  it.todo("claim for item not in policy exits with error");
  it.todo("negative damage amount exits with error");
});

export function processScenario(scenario: unknown): unknown[] {
  return [];
}

